def test_render_engine():
    """测试渲染引擎的谓词验证"""
    print("\n" + "=" * 60)
    print("渲染引擎谓词验证测试")
    print("=" * 60)

    engine = RenderEngine()

    # 创建测试点
    engine.add_point("A", 0, 0)
    engine.add_point("B", 2, 0)
    engine.add_point("C", 1, math.sqrt(3))  # 等边三角形
    engine.add_point("D", 1, 0)  # AB 的中点
    engine.add_point("M", 1, 0)  # AB 的中点
    # O 是等边三角形的外心 (1, sqrt(3)/3)
    engine.add_point("O", 1, math.sqrt(3) / 3)

    # 创建更多测试点用于等角/等比测试
    engine.add_point("E", 0, 2)
    engine.add_point("F", 2, 2)
    engine.add_point("G", 3, 0)
    engine.add_point("H", 3, 2)

    tests = [
        # 基本谓词
        ("coll A B D", True, "共线验证"),
        ("coll A B C", False, "不共线验证"),
        ("midp M A B", True, "中点验证"),
        ("para A B E F", True, "平行验证 (AB // EF)"),
        ("perp A B A E", True, "垂直验证 (AB ⊥ AE)"),
        ("cong A B E F", True, "全等验证 (AB = EF)"),
        # 等角谓词
        ("eqangle A B A B A B A B", True, "等角验证 (相同线)"),
        ("eqangle A B E F E F A B", True, "等角验证 (交换)"),
        # 等比谓词
        ("eqratio A B E F E F A B", True, "等比验证 (AB/EF = EF/AB)"),
        ("eqratio A B A B A B A B", True, "等比验证 (相同长度)"),
        # 圆谓词 - O 是外心，所以 OA = OB = OC
        ("circle O A B C", True, "圆验证 (O 是外心)"),
        # 共圆谓词 - A, B, C, D 不共圆
        ("cyclic A B C D", False, "共圆验证"),
    ]

    print("\n谓词验证结果:")
    all_passed = True
    for prop_str, expected, desc in tests:
        try:
            prop = GeometryParser.parse_proposition(prop_str)
            result = engine.verify_proposition(prop)
            status = "✓" if result == expected else "✗"
            if result != expected:
                all_passed = False
                print(f"  {status} {desc}: {prop_str}")
                print(f"      期望: {expected}, 实际: {result}")
            else:
                print(f"  {status} {desc}: {prop_str}")
        except Exception as e:
            print(f"  ✗ {desc}: {prop_str}")
            print(f"      错误: {e}")
            all_passed = False

    return all_passed


